#include <iostream>
#include <vector>

int main() {
    std::size_t count{};
    if (!(std::cin >> count) || count > 100) return 1;
    std::vector<int> values(count);
    for (int& value : values) if (!(std::cin >> value)) return 1;
    for (std::size_t i = values.size(); i > 0; --i) {
        if (i != values.size()) std::cout << ' ';
        std::cout << values[i - 1];
    }
    std::cout << '\n';
}
